// Lightweight loader to pull Chart.js from CDN so you don't have to bundle it.
// Chart.js will be available globally as Chart once loaded.
(function loadChart() {
  if (window.Chart) return;
  const url = "https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js";
  window.chartReady = new Promise((resolve, reject) => {
    const s = document.createElement("script");
    s.src = url; s.async = true;
    s.onload = () => resolve(window.Chart);
    s.onerror = reject;
    document.head.appendChild(s);
  });
})(); 


